(title) => {
  const titleRoot = document.querySelector('div.client_components_titleInput');
  const editor = titleRoot ? titleRoot.querySelector('[contenteditable="true"]') : null;
  if (editor) {
    editor.focus();
    editor.innerText = '';
    editor.dispatchEvent(new Event('input', { bubbles: true }));
    editor.innerText = title;
    try {
      editor.dispatchEvent(new InputEvent('input', { bubbles: true, data: title, inputType: 'insertText' }));
    } catch (e) {
      editor.dispatchEvent(new Event('input', { bubbles: true }));
    }
    editor.dispatchEvent(new Event('change', { bubbles: true }));
    editor.dispatchEvent(new KeyboardEvent('keyup', { bubbles: true, key: 'a' }));
    editor.dispatchEvent(new Event('blur', { bubbles: true }));
    return { success: true };
  }
  const elements = document.querySelectorAll('[contenteditable="true"]');
  for (const el of elements) {
    const t = (el.closest('div')?.textContent || '');
    if (t.includes('请输入标题') || t.includes('标题（')) {
      el.focus();
      el.innerText = title;
      el.dispatchEvent(new Event('input', { bubbles: true }));
      return { success: true };
    }
  }
  return { success: false };
}

(content) => {
  const inst = window.UE_V2 && window.UE_V2.instants && window.UE_V2.instants.ueditorInstant0;
  if (inst && typeof inst.execCommand === 'function') {
    try { inst.execCommand('cleardoc'); } catch (e) {}
    try {
      inst.execCommand('insertHtml', content);
      return { success: true };
    } catch (e) {}
  }
  const iframe = document.querySelector('iframe');
  if (iframe && iframe.contentDocument && iframe.contentDocument.body) {
    const editor = iframe.contentDocument.body.querySelector('[contenteditable="true"]');
    if (editor) {
      editor.innerHTML = content;
      editor.dispatchEvent(new Event('input', { bubbles: true }));
      editor.dispatchEvent(new Event('change', { bubbles: true }));
      return { success: true };
    }
    iframe.contentDocument.body.innerHTML = content;
    iframe.contentDocument.body.dispatchEvent(new Event('input', { bubbles: true }));
    return { success: true };
  }
  return { success: false };
}

() => {
  const root = document.getElementById('bjhNewsCover');
  const txt = root ? (root.textContent || '') : '';
  if (!txt.includes('选择封面')) return { skipped: true };
  const icon = document.querySelector('#bjhNewsCover ._73a3a52aab7e3a36-icon');
  if (icon) { icon.click(); return { success: true }; }
  const fallback = Array.from(document.querySelectorAll('*')).find(el => (el.textContent || '').replace(/\s+/g,'').trim() === '选择封面');
  if (fallback) { fallback.click(); return { success: true }; }
  return { success: false };
}

() => {
  const wrap = document.querySelector('.cheetah-modal-wrap');
  if (!wrap) return { success: false };
  const tabs = Array.from(wrap.querySelectorAll('[role=tab]'));
  const tab = tabs.find(t => (t.textContent || '').replace(/\s+/g,'').includes('正文'));
  if (tab) { tab.click(); return { success: true }; }
  return { success: false };
}

() => new Promise(resolve => {
  let attempts = 0;
  const check = () => {
    const wrap = document.querySelector('.cheetah-modal-wrap');
    if (!wrap) { resolve({ ok: false }); return; }
    const btns = Array.from(wrap.querySelectorAll('button'));
    const ok = btns.find(b => (b.textContent || '').replace(/\s+/g,'').trim() === '确定');
    if (ok && !ok.disabled) { resolve({ ok: true }); return; }
    if (++attempts < 60) setTimeout(check, 300); else resolve({ ok: false });
  };
  check();
})

() => { const norm = (s) => (s || '').replace(/\s+/g, ' ').trim(); const isVisible = (el) => { if (!el) return false; const style = window.getComputedStyle(el); if (!style || style.visibility === 'hidden' || style.display === 'none') return false; const rect = el.getBoundingClientRect(); return rect.width > 0 && rect.height > 0; }; const candidates = Array.from(document.querySelectorAll('label, button, span, div')).filter(isVisible); const immediate = candidates.find(el => /立即发布|立即发表|立即/.test(norm(el.textContent || ''))); if (immediate) { const clickable = immediate.closest('label, button, [role="button"]') || immediate; clickable.click(); return { mode: 'immediate', clicked: true }; }
  const labelFor = Array.from(document.querySelectorAll('label')).find(el => /立即发布|立即发表|立即/.test(norm(el.textContent || '')));
  if (labelFor) { labelFor.click(); return { mode: 'immediate', clicked: true, via: 'label' }; }
  const inputImmediate = Array.from(document.querySelectorAll('input[type=radio], input[type=checkbox]')).find(el => /now|immediate|publish_now/.test((el.value || '') + ' ' + (el.name || '')));
  if (inputImmediate) { inputImmediate.click(); return { mode: 'immediate', clicked: true, via: 'input' }; }
  const scheduled = candidates.find(el => /定时发布|预约发布|定时|预约/.test(norm(el.textContent || '')));
  if (scheduled && scheduled.getAttribute('aria-checked') === 'true') { return { mode: 'scheduled', clicked: false }; }
  return { mode: 'unknown', clicked: false }; }

() => { const norm = (s) => (s || '').replace(/\s+/g, ' ').trim(); const isVisible = (el) => { if (!el) return false; const style = window.getComputedStyle(el); if (!style || style.visibility === 'hidden' || style.display === 'none') return false; const rect = el.getBoundingClientRect(); return rect.width > 0 && rect.height > 0; }; const toggles = Array.from(document.querySelectorAll('label, button, span, div')).filter(isVisible).filter(el => /定时发布|预约发布|定时|预约/.test(norm(el.textContent || ''))); const active = toggles.find(el => el.getAttribute('aria-checked') === 'true' || el.classList.contains('active') || el.classList.contains('checked') || el.classList.contains('selected')); if (active) { const clickable = active.closest('label, button, [role="button"]') || active; clickable.click(); return { disabled: true }; }
  const scheduleInput = Array.from(document.querySelectorAll('input[type=checkbox], input[type=radio]')).find(el => /schedule|timed|预约|定时/.test((el.name || '') + ' ' + (el.value || '')) && (el.checked || el.getAttribute('aria-checked') === 'true'));
  if (scheduleInput) { scheduleInput.click(); return { disabled: true, via: 'input' }; }
  return { disabled: false }; }
